```csharp
public class SentimentApiHealthCheck : IHealthCheck
{
    private readonly HttpClient _httpClient;
    public SentimentApiHealthCheck(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    public async Task<HealthCheckResult> CheckHealthAsync(
        HealthCheckContext context,
        CancellationToken cancellationToken = default)
    {
        try
        {
            using var cts = CancellationTokenSource.CreateLinkedTokenSource(cancellationToken);
            cts.CancelAfter(TimeSpan.FromMilliseconds(500));
            var response = await _httpClient.GetAsync("/ping", cts.Token);
            if (response.IsSuccessStatusCode)
                return HealthCheckResult.Healthy("Sentiment API répond correctement.");
            return HealthCheckResult.Degraded($"API retourne {response.StatusCode}");
        }
        catch (TaskCanceledException)
        {
            return HealthCheckResult.Unhealthy("Timeout > 500 ms.");
        }
        catch (Exception ex)
        {
            return HealthCheckResult.Unhealthy(ex.Message);
        }
    }
}
```
